\begin{flalign*}
\cos{\delta_x}=\cos\frac{c}{c_x}=\frac{\gamma_c}{1/\beta_v\beta_c}
=\frac{v_xc_x}{c^2\sqrt{1-\frac{c_x^2}{c^2}}}=\frac{v_xc_x}{c\sqrt{c^2-c_x^2}}=\frac{v_xc_x}{cv_x}
=\frac{c_x}{c}=\beta_c=\frac{1}{\delta_x}&&
